function BaseAreaEvent:onEnd()
    self:playSound(self.config.eventSound[2])
    Utility.playEffect(self.config.eventEffect[2])
    self:doReward()
    EngineWorld:stopWorldTime(self.config.serverTime[2])
end

function BaseAreaEvent:isEnd()
    return self:getLiveTime() >= self.config.eventTime
end

